# Functions & Scope

## Function Declaration

```js
function greet(name) {
  return `Hello, ${name}!`;
}
```

## Arrow Functions

```js
const greet = (name) => `Hello, ${name}!`;

// Multi-line arrow function
const add = (a, b) => {
  const result = a + b;
  return result;
};
```

## Default Parameters

```js
const greet = (name = 'Stranger') => `Hello, ${name}!`;
greet();         // Hello, Stranger!
greet('Alice');  // Hello, Alice!
```

## Scope

```js
let x = 'global';

function test() {
  let x = 'local'; // different variable
  console.log(x);  // 'local'
}

console.log(x); // 'global'
```

## Closures

```js
function counter() {
  let count = 0;
  return () => ++count;
}

const increment = counter();
increment(); // 1
increment(); // 2
increment(); // 3
```

# Arrays & Objects

## Array Methods

```js
const nums = [1, 2, 3, 4, 5];

nums.map(n => n * 2);        // [2, 4, 6, 8, 10]
nums.filter(n => n > 2);     // [3, 4, 5]
nums.reduce((acc, n) => acc + n, 0); // 15
nums.find(n => n > 3);       // 4
nums.includes(3);            // true
```

## Destructuring

```js
// Array destructuring
const [first, second, ...rest] = [1, 2, 3, 4];
// first=1, second=2, rest=[3,4]

// Object destructuring
const { name, age, city = 'Unknown' } = user;
```

## Spread Operator

```js
const arr1 = [1, 2, 3];
const arr2 = [...arr1, 4, 5]; // [1,2,3,4,5]

const obj1 = { a: 1 };
const obj2 = { ...obj1, b: 2 }; // {a:1, b:2}
```

## Object Methods

```js
const user = { name: 'Alice', age: 25 };

Object.keys(user);    // ['name', 'age']
Object.values(user);  // ['Alice', 25]
Object.entries(user); // [['name','Alice'],['age',25]]
```

# Components & JSX

## What is a Component?

A component is a reusable piece of UI â€” like a LEGO brick.

```tsx
function Button({ label, onClick }) {
  return (
    <button onClick={onClick}>
      {label}
    </button>
  );
}
```

## JSX Rules

```tsx
// 1. Single root element
return (
  <div>
    <h1>Hello</h1>
    <p>World</p>
  </div>
);

// 2. Use className, not class
<div className="container">

// 3. Self-close empty elements
<img src="img.png" />
<input type="text" />

// 4. JavaScript in curly braces
<p>{2 + 2}</p>          // 4
<p>{user.name}</p>      // Alice
```

## Props

```tsx
function Card({ title, description, image }) {
  return (
    <div className="card">
      <img src={image} alt={title} />
      <h2>{title}</h2>
      <p>{description}</p>
    </div>
  );
}

// Usage
<Card
  title="React Course"
  description="Learn React"
  image="/img/react.png"
/>
```

# useState & useEffect

## useState

```tsx
import { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={() => setCount(count + 1)}>
        Increment
      </button>
    </div>
  );
}
```

## State with Objects

```tsx
const [user, setUser] = useState({ name: '', age: 0 });

// Always spread when updating objects!
setUser(prev => ({ ...prev, name: 'Alice' }));
```

## useEffect

```tsx
import { useEffect } from 'react';

// Runs after every render
useEffect(() => {
  console.log('rendered!');
});

// Runs once on mount
useEffect(() => {
  fetchData();
}, []);

// Runs when count changes
useEffect(() => {
  document.title = `Count: ${count}`;
}, [count]);

// Cleanup
useEffect(() => {
  const timer = setInterval(() => {}, 1000);
  return () => clearInterval(timer); // cleanup!
}, []);
```

# Custom Hooks

Custom hooks let you extract and reuse stateful logic.

## Rules of Hooks

1. Only call hooks at the **top level**
2. Only call hooks from **React functions**
3. Name always starts with **use**

## Example: useFetch

```tsx
function useFetch<T>(url: string) {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetch(url)
      .then(res => res.json())
      .then(data => {
        setData(data);
        setLoading(false);
      })
      .catch(err => {
        setError(err.message);
        setLoading(false);
      });
  }, [url]);

  return { data, loading, error };
}

// Usage
const { data, loading, error } = useFetch('/api/courses');
```

## Example: useDebounce

```tsx
function useDebounce<T>(value: T, delay: number): T {
  const [debounced, setDebounced] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);

  return debounced;
}
```

# Types & Interfaces

## Basic Types

```ts
let name: string = 'Alice';
let age: number = 25;
let active: boolean = true;
let data: null = null;
let id: undefined = undefined;
```

## Arrays & Tuples

```ts
let nums: number[] = [1, 2, 3];
let strs: Array<string> = ['a', 'b'];

// Tuple â€” fixed length, known types
let pair: [string, number] = ['Alice', 25];
```

## Interface

```ts
interface User {
  id: number;
  name: string;
  email: string;
  age?: number; // optional
  readonly createdAt: Date; // read-only
}

const user: User = {
  id: 1,
  name: 'Alice',
  email: 'alice@example.com',
  createdAt: new Date(),
};
```

## Type Alias

```ts
type Status = 'active' | 'inactive' | 'pending';
type ID = string | number;

type Course = {
  id: string;
  title: string;
  lessons: string[];
};
```

# Generics

Generics let you write reusable, type-safe code.

## Basic Generic

```ts
function identity<T>(value: T): T {
  return value;
}

identity<string>('hello'); // string
identity<number>(42);      // number
```

## Generic Interface

```ts
interface ApiResponse<T> {
  data: T;
  status: number;
  message: string;
}

type UserResponse = ApiResponse<User>;
type CoursesResponse = ApiResponse<Course[]>;
```

## Generic Constraints

```ts
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

const user = { name: 'Alice', age: 25 };
getProperty(user, 'name'); // 'Alice'
getProperty(user, 'xyz');  // Error! 'xyz' not in user
```

## Generic React Component

```tsx
interface ListProps<T> {
  items: T[];
  renderItem: (item: T) => ReactNode;
}

function List<T>({ items, renderItem }: ListProps<T>) {
  return <ul>{items.map(renderItem)}</ul>;
}
```

# Utility Types

TypeScript ships with built-in utility types.

## Partial & Required

```ts
interface User {
  name: string;
  age: number;
  email: string;
}

type PartialUser = Partial<User>;
// { name?: string; age?: number; email?: string }

type RequiredUser = Required<PartialUser>;
// All fields required again
```

## Pick & Omit

```ts
type UserPreview = Pick<User, 'name' | 'email'>;
// { name: string; email: string }

type UserWithoutAge = Omit<User, 'age'>;
// { name: string; email: string }
```

## Record

```ts
type Scores = Record<string, number>;
const scores: Scores = { quiz1: 90, quiz2: 85 };
```

## ReturnType & Parameters

```ts
function fetchUser(id: number): Promise<User> { ... }

type FetchReturn = ReturnType<typeof fetchUser>;
// Promise<User>

type FetchParams = Parameters<typeof fetchUser>;
// [id: number]
```

# CSS Fundamentals

## The Box Model

Every element is a box with:
- **Content** â€” the actual content
- **Padding** â€” space inside the border
- **Border** â€” the border line
- **Margin** â€” space outside the border

```css
.box {
  width: 200px;
  padding: 16px;
  border: 2px solid #333;
  margin: 24px;
  box-sizing: border-box; /* padding included in width */
}
```

## Flexbox

```css
.container {
  display: flex;
  justify-content: space-between; /* horizontal */
  align-items: center;            /* vertical */
  gap: 16px;
  flex-wrap: wrap;
}
```

## Grid

```css
.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  grid-template-rows: auto;
  gap: 24px;
}

/* Responsive grid */
.grid {
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
}
```

# Animations & Transitions

## CSS Transitions

```css
.button {
  background: blue;
  transform: scale(1);
  transition: all 0.2s ease-in-out;
}

.button:hover {
  background: darkblue;
  transform: scale(1.05);
}
```

## CSS Keyframes

```css
@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to   { opacity: 1; transform: translateY(0); }
}

.card {
  animation: fadeIn 0.3s ease-out forwards;
}
```

## Framer Motion (React)

```tsx
import { motion } from 'framer-motion';

// Basic animation
<motion.div
  initial={{ opacity: 0, y: 20 }}
  animate={{ opacity: 1, y: 0 }}
  transition={{ duration: 0.4 }}
>

// Hover animation
<motion.button
  whileHover={{ scale: 1.05 }}
  whileTap={{ scale: 0.95 }}
>

// Page transition
<motion.div
  initial={{ opacity: 0 }}
  animate={{ opacity: 1 }}
  exit={{ opacity: 0 }}
>
```
